import dspy
import vex

class ClaimReview(dspy.Signature):
    '''Review insurance claim for approval.'''
    claim_description: str = dspy.InputField()
    policy_details: str = dspy.InputField()
    decision: str = dspy.OutputField(desc='approve|deny')
    reason: str = dspy.OutputField(desc='Specific, explainable reason')

@vex.verify({
    'no_pii_leak': 'reason does not contain SSN, DOB, or address',
    'explainable_denial': "decision=='deny' => len(reason)>50 and 'insufficient' not in reason.lower()",
    'no_protected_classes': 'reason not contains race, gender, age, ethnicity'
})
def verify_claim_review(**kwargs):
    return kwargs

class ClaimsModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.review = ClaimReview()

    def forward(self, claim_description, policy_details):
        prediction = self.review(claim_description=claim_description, policy_details=policy_details)
        return vex.verify_and_return('claims-compliance', prediction, verify_claim_review)

import dspy
import vex
import numpy as np

class UnderwritingRisk(dspy.Signature):
    applicant_profile: str = dspy.InputField()
    risk_score: float = dspy.OutputField(desc='0-1 risk probability')
    factors: list = dspy.OutputField(desc='Top 3 risk factors')

@vex.verify({
    'no_proxy_discrimination': 'any(f in factors for f in ["zipcode", "postal", "neighborhood"]) == False',
    'score_bounds': '0 <= risk_score <= 1',
    'explainable_factors': 'len(factors) == 3 and all(len(f)>10 for f in factors)'
})
def verify_underwriting(**kwargs):
    return kwargs

class RiskModel(dspy.Module):
    def __init__(self):
        super().__init__()
        self.underwrite = UnderwritingRisk()

    def forward(self, applicant_profile):
        pred = self.underwrite(applicant_profile=applicant_profile)
        # Vex catches failures during DSPy optimization
        verified = vex.verify_and_return('underwriting-fairness', pred, verify_underwriting)
        return verified

import dspy
import vex

from typing import List

class PolicyRenewalCoT(dspy.Signature):
    '''Chain-of-thought renewal decision.'''
    policy_history: str = dspy.InputField()
    customer_profile: str = dspy.InputField()
    reasoning: str = dspy.OutputField()
    renew: bool = dspy.OutputField()
    premium_adjustment: float = dspy.OutputField()

@vex.verify({
    'no_pii_in_reasoning': 'not any(pii in reasoning.lower() for pii in ["ssn", "dob", "address", "phone"])',
    'valid_premium': '0.5 <= premium_adjustment <= 2.0',
    'cot_length': 'len(reasoning.split()) > 20',
    'audit_log': True
})
def verify_renewal_cot(**kwargs):
    return kwargs

class RenewalModule(dspy.Module):
    def forward(self, policy_history, customer_profile):
        prediction = PolicyRenewalCoT()(
            policy_history=policy_history,
            customer_profile=customer_profile
        )
        return vex.verify_and_return('renewal-compliance', prediction, verify_renewal_cot)
